#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cmath>
#include <vector>
#include "cJSON.h"
#include "lodepng.h"

static std::vector<std::vector<double>> get2d(cJSON *root, const char *name) {
    cJSON *arr = cJSON_GetObjectItem(root, name);
    std::vector<std::vector<double>> out;
    cJSON *row;
    cJSON_ArrayForEach(row, arr) {
        std::vector<double> r;
        cJSON *v;
        cJSON_ArrayForEach(v, row) r.push_back(v->valuedouble);
        out.push_back(r);
    }
    return out;
}

static std::vector<double> get1d(cJSON *root, const char *name) {
    cJSON *arr = cJSON_GetObjectItem(root, name);
    std::vector<double> out;
    cJSON *v;
    cJSON_ArrayForEach(v, arr) out.push_back(v->valuedouble);
    return out;
}

// y = W x + b, with ReLU optional
static std::vector<double> linear(const std::vector<std::vector<double>>& W,
                                  const std::vector<double>& b,
                                  const std::vector<double>& x, bool relu) {
    std::vector<double> y(W.size());
    for (size_t i = 0; i < W.size(); ++i) {
        double s = b[i];
        const std::vector<double>& row = W[i];
        for (size_t j = 0; j < row.size(); ++j) s += row[j] * x[j];
        if (relu && s < 0) s = 0;
        y[i] = s;
    }
    return y;
}

int main(int argc, char** argv) {
    if (argc != 3) {
        fprintf(stderr, "usage: %s weights.json image.png\n", argv[0]);
        return 1;
    }

    // read weights.json
    FILE* f = fopen(argv[1], "rb");
    if (!f) { fprintf(stderr, "cannot open %s\n", argv[1]); return 1; }
    fseek(f, 0, SEEK_END); long sz = ftell(f); fseek(f, 0, SEEK_SET);
    std::vector<char> buf(sz + 1);
    if (fread(buf.data(), 1, sz, f) != (size_t)sz) { fclose(f); return 1; }
    buf[sz] = 0; fclose(f);

    cJSON* root = cJSON_Parse(buf.data());
    if (!root) { fprintf(stderr, "json parse error\n"); return 1; }

    auto W1 = get2d(root, "input_layer.weight");
    auto b1 = get1d(root, "input_layer.bias");
    auto W2 = get2d(root, "hidden_layer.weight");
    auto b2 = get1d(root, "hidden_layer.bias");
    auto W3 = get2d(root, "output_layer.weight");
    auto b3 = get1d(root, "output_layer.bias");

    // decode PNG (grayscale)
    std::vector<unsigned char> img;
    unsigned w, h;
    unsigned err = lodepng::decode(img, w, h, argv[2], LCT_GREY, 8);
    if (err) { fprintf(stderr, "png decode error: %s\n", lodepng_error_text(err)); return 1; }

    // preprocess: /255 then MNIST normalize (mean 0.1307, std 0.3081)
    std::vector<double> x(w * h);
    const double mean = 0.1307, std = 0.3081;
    for (size_t i = 0; i < x.size(); ++i)
        x[i] = ((img[i] / 255.0) - mean) / std;

    auto h1 = linear(W1, b1, x, true);
    auto h2 = linear(W2, b2, h1, true);
    auto out = linear(W3, b3, h2, false);

    int best = 0;
    for (size_t i = 1; i < out.size(); ++i)
        if (out[i] > out[best]) best = (int)i;

    printf("%d\n", best);

    cJSON_Delete(root);
    return 0;
}

